mapper.sql:
where b.tenant_id = #{tenantId} and b.del_flag = 0
and b.batch_status = #{statusCode}
and ( b.batch_no like concat('%', #{keyword}, '%') or b.statement_file_name like concat('%', #{keyword}, '%') or b.file_digest like concat('%', #{keyword}, '%') or b.importer_name like concat('%', #{keyword}, '%') or b.bank_account_no_mask like concat('%', #{keyword}, '%') or b.bank_name like concat('%', #{keyword}, '%') )

mapper.select:

from payment_offline_bank_statement_batch b

order by b.created_at desc
limit #{limit} offset #{offset}


from payment_offline_bank_statement_batch b
where b.tenant_id = #{tenantId}
  and b.del_flag = 0
  and b.id = #{id}
limit 1

select count(1)
from payment_offline_bank_statement_batch b
where b.tenant_id = #{tenantId}
  and b.file_digest = #{fileDigest}
  and b.del_flag = 0

mapper.update:
update payment_offline_bank_statement_batch b
set b.total_count = (
        select count(1)
        from payment_offline_bank_statement_item i
        where i.tenant_id = #{tenantId}
          and i.batch_id = #{id}
          and i.del_flag = 0
    ),
    b.matched_count = (
        select count(1)
        from payment_offline_bank_statement_item i
        where i.tenant_id = #{tenantId}
          and i.batch_id = #{id}
          and i.del_flag = 0
          and i.match_status in ('MATCHED_PENDING_CONFIRM', 'CONFIRMED')
    ),
    b.confirmed_count = (
        select count(1)
        from payment_offline_bank_statement_item i
        where i.tenant_id = #{tenantId}
          and i.batch_id = #{id}
          and i.del_flag = 0
          and i.match_status = 'CONFIRMED'
    ),
    b.difference_count = (
        select count(1)
        from payment_offline_bank_statement_item i
        where i.tenant_id = #{tenantId}
          and i.batch_id = #{id}
          and i.del_flag = 0
          and i.match_status not in ('MATCHED_PENDING_CONFIRM', 'CONFIRMED')
    ),
    b.batch_status = case
        when (
            select count(1)
            from payment_offline_bank_statement_item i
            where i.tenant_id = #{tenantId}
              and i.batch_id = #{id}
              and i.del_flag = 0
              and i.match_status not in ('MATCHED_PENDING_CONFIRM', 'CONFIRMED')
        ) > 0 then 'DIFFERENCE'
        when (
            select count(1)
            from payment_offline_bank_statement_item i
            where i.tenant_id = #{tenantId}
              and i.batch_id = #{id}
              and i.del_flag = 0
              and i.match_status = 'MATCHED_PENDING_CONFIRM'
        ) = 0 then 'CONFIRMED'
        else 'MATCHED'
    end,
    b.updated_at = now()
where b.tenant_id = #{tenantId}
  and b.id = #{id}
  and b.del_flag = 0
